            // First time user goes to TOS, returning user skips to form
            withAnimation {
                step = isReturning ? .form : .tos
            }
        }
    }

    private var isFormValid: Bool {
        !eventName.trimmingCharacters(in: .whitespaces).isEmpty &&
        validOutcomes.count >= 2
    }

    private var validOutcomes: [String] {
        outcomes.filter { !$0.trimmingCharacters(in: .whitespaces).isEmpty }
    }

    private func tosSection(_ title: String, _ body: String) -> some View {
        VStack(alignment: .leading, spacing: 6) {
            Text(title)
                .font(.custom("DM Mono", size: 12))
                .kerning(1)
                .foregroundColor(ClipBetColors.textPrimary)
            Text(body)
                .font(.custom("DM Mono", size: 11))
                .foregroundColor(ClipBetColors.textSecondary)
                .lineSpacing(3)
        }
    }
}

// MARK: - From Submissions/clipbet/ClipBetDashboard.swift

//  ClipBetDashboard.swift
//  ClipBet
//
//  Organizer dashboard showing live pool stats.
//  Includes Resolve, Cancel, Close Bets, and Share QR actions.
//

import SwiftUI

// MARK: - Dashboard Experience (Standalone Entry Point)

struct ClipBetDashboardExperience: ClipExperience {
    static let urlPattern = "clipbet.io/dashboard/:eventId"
    static let clipName = "ClipBet Dashboard"
    static let clipDescription = "Manage your prediction market. Resolve outcomes and distribute winnings."
    static let teamName = "ClipBet"

    static let touchpoint: JourneyTouchpoint = .onSite
    static let invocationSource: InvocationSource = .qrCode

    let context: ClipContext

    var body: some View {
        OrganizerDashboard()
    }
}

// MARK: - Dashboard View

struct OrganizerDashboard: View {
    @State private var event: PredictionEvent = ClipBetMockData.primaryEvent
    @State private var showResolveSheet = false
    @State private var showCancelConfirm = false
    @State private var showCloseConfirm = false
    @State private var selectedWinner: BetOutcome?
    @State private var showResolveConfirm = false
    @State private var appeared = false
    @State private var paymentManager = ClipBetPaymentManager()

    var body: some View {
        ZStack {
            ClipBetColors.bg.ignoresSafeArea()

            ScrollView {
                VStack(spacing: 0) {
                    // Header
                    VStack(spacing: 12) {
                        Text("Dashboard")
                            .font(.custom("Cormorant Garamond", size: 28))
                            .fontWeight(.light)
                            .foregroundColor(ClipBetColors.textPrimary)
                            .opacity(appeared ? 1 : 0)
                            .offset(y: appeared ? 0 : 8)

                        StatusIndicator(status: event.status)
                    }
                    .padding(.top, 24)
                    .padding(.bottom, 20)

                    ClipBetDivider()

                    // Event name
                    Text(event.name)
                        .font(.custom("Cormorant Garamond", size: 22))
                        .fontWeight(.light)
                        .foregroundColor(ClipBetColors.textPrimary)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal, 32)
                        .padding(.vertical, 20)

                    ClipBetDivider()

                    // Pool stats
                    HStack(spacing: 0) {
                        StatColumn(value: event.formattedPool, label: "TOTAL POOL")
                        ClipBetVerticalDivider()
                        StatColumn(value: "\(event.totalBettors)", label: "BETTORS")
                    }
                    .padding(.vertical, 16)

                    HStack(spacing: 0) {
                        StatColumn(value: String(format: "$%.0f", event.platformFee), label: "PLATFORM FEE 5%")
                        ClipBetVerticalDivider()
                        StatColumn(value: String(format: "$%.0f", event.winnerPool), label: "WINNER POOL")
                    }
                    .padding(.vertical, 16)

                    MonoLabel(text: "Started \(event.timeSinceCreated) ago")
                        .padding(.bottom, 16)

                    ClipBetDivider()

                    // Outcomes with animated bars
                    VStack(spacing: 0) {
                        ForEach(Array(event.outcomes.enumerated()), id: \.element.id) { index, outcome in
                            dashboardOutcomeRow(outcome: outcome, index: index)

                            if index < event.outcomes.count - 1 {
                                ClipBetDivider()
                            }
                        }
                    }
                    .padding(.horizontal, 24)
                    .padding(.vertical, 16)

                    ClipBetDivider()

                    // Actions
                    VStack(spacing: 12) {
                        if event.status == .live {
                            // Close Bets
                            ClipBetSecondaryButton(title: "CLOSE BETS") {
                                showCloseConfirm = true
                            }

                            // Resolve
                            ClipBetPrimaryButton(title: "RESOLVE EVENT", icon: "checkmark.circle") {
                                showResolveSheet = true
                            }

                            // Cancel
                            Button {
                                showCancelConfirm = true
                            } label: {
                                Text("CANCEL & REFUND ALL")
                                    .font(.custom("DM Mono", size: 11))
                                    .kerning(1.4)
                                    .foregroundColor(ClipBetColors.no)
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 14)
                                    .overlay(
                                        RoundedRectangle(cornerRadius: 2)
                                            .stroke(ClipBetColors.noFill, lineWidth: 1)
                                    )
                            }
                        } else if event.status == .betsClosed {
                            ClipBetPrimaryButton(title: "RESOLVE EVENT", icon: "checkmark.circle") {
                                showResolveSheet = true
                            }

                            Button {
                                showCancelConfirm = true
                            } label: {
                                Text("CANCEL & REFUND ALL")
                                    .font(.custom("DM Mono", size: 11))
                                    .kerning(1.4)
                                    .foregroundColor(ClipBetColors.no)
                                    .frame(maxWidth: .infinity)
                                    .padding(.vertical, 14)
                                    .overlay(
                                        RoundedRectangle(cornerRadius: 2)
                                            .stroke(ClipBetColors.noFill, lineWidth: 1)
                                    )
                            }
                        } else if event.status == .resolved {
                            resolvedBanner
                        } else if event.status == .cancelled {
                            cancelledBanner
                        }

                        // Share QR
                        ClipBetSecondaryButton(title: "VIEW & SHARE QR") { }
                    }
                    .padding(.horizontal, 24)
                    .padding(.vertical, 24)
                }
            }
            .scrollIndicators(.hidden)

            // Resolve sheet
            if showResolveSheet {
                resolveSheet
            }

            // Cancel confirmation
            if showCancelConfirm {
                cancelConfirmOverlay
            }

            // Close bets confirmation
            if showCloseConfirm {
                closeConfirmOverlay
            }
        }
        .onAppear {
            withAnimation(.easeOut(duration: 0.6).delay(0.1)) {
                appeared = true
            }
        }
    }

    // MARK: - Dashboard Outcome Row

    private func dashboardOutcomeRow(outcome: BetOutcome, index: Int) -> some View {
        let pct = event.percentage(for: outcome)
        let isFirst = index == 0
        let color = isFirst ? ClipBetColors.yes : ClipBetColors.no
        let isWinner = event.resolvedOutcomeId == outcome.id

        return VStack(alignment: .leading, spacing: 8) {
            HStack {
                Text(outcome.name)
                    .font(.custom("DM Mono", size: 14))
                    .foregroundColor(ClipBetColors.textPrimary)

                if isWinner {
                    ClipBetTag(text: "WINNER", color: ClipBetColors.yes)
                }

                Spacer()

                Text(String(format: "%.0f%%", pct))
                    .font(.custom("Cormorant Garamond", size: 28))
                    .fontWeight(.light)
                    .foregroundColor(color)
            }

            // Animated progress bar
            GeometryReader { geo in
                ZStack(alignment: .leading) {
                    Rectangle()
                        .fill(ClipBetColors.divider)
                        .frame(height: 4)

                    Rectangle()
                        .fill(color)
                        .frame(width: appeared ? geo.size.width * (pct / 100) : 0, height: 4)
                        .animation(.easeOut(duration: 0.8).delay(Double(index) * 0.15), value: appeared)
                }
            }
            .frame(height: 4)

            HStack {
                Text(outcome.formattedAmount)
                    .font(.custom("DM Mono", size: 11))
                    .foregroundColor(ClipBetColors.textSecondary)
                Spacer()
                Text("\(outcome.betCount) bets")
                    .font(.custom("DM Mono", size: 11))
                    .foregroundColor(ClipBetColors.textFaint)
            }
        }
        .padding(.vertical, 16)
    }

    // MARK: - Resolve Sheet

    private var resolveSheet: some View {
        ZStack {
            Color.black.opacity(0.5).ignoresSafeArea()
                .onTapGesture {
                    withAnimation { showResolveSheet = false }
                }

            VStack(spacing: 0) {
                Spacer()

                VStack(spacing: 0) {
                    // Header
                    HStack {
                        Button {
                            withAnimation { showResolveSheet = false }
                        } label: {
                            Image(systemName: "xmark")
                                .font(.system(size: 14))
                                .foregroundColor(ClipBetColors.textFaint)
                        }
                        Spacer()
                    }
                    .padding(.horizontal, 24)
                    .padding(.top, 20)

                    Text("Resolve Event")
                        .font(.custom("Cormorant Garamond", size: 24))
                        .fontWeight(.light)
                        .foregroundColor(ClipBetColors.bg)
                        .padding(.top, 8)
                        .padding(.bottom, 4)

                    MonoLabel(text: "SELECT THE WINNING OUTCOME")
                        .padding(.bottom, 20)

                    ClipBetDarkDivider()

                    // Outcome selection
                    ForEach(event.outcomes) { outcome in
                        let isSelected = selectedWinner?.id == outcome.id
                        let isFirst = event.outcomes.first?.id == outcome.id
                        let pct = event.percentage(for: outcome)

                        Button {
                            selectedWinner = outcome
                        } label: {
                            HStack {
                                Circle()
                                    .fill(isSelected ? (isFirst ? ClipBetColors.yes : ClipBetColors.no) : ClipBetColors.textFaint)
                                    .frame(width: 10, height: 10)

                                VStack(alignment: .leading, spacing: 2) {
                                    Text(outcome.name)
                                        .font(.custom("DM Mono", size: 14))
                                        .foregroundColor(isSelected ? .white : ClipBetColors.textFaint)
                                    Text("\(outcome.betCount) bettors share \(String(format: "$%.0f", event.winnerPool))")
                                        .font(.custom("DM Mono", size: 10))
                                        .foregroundColor(ClipBetColors.textFaint)
                                }

                                Spacer()

                                Text(String(format: "%.0f%%", pct))
                                    .font(.custom("Cormorant Garamond", size: 22))
                                    .fontWeight(.light)
                                    .foregroundColor(isSelected ? (isFirst ? ClipBetColors.yes : ClipBetColors.no) : ClipBetColors.textFaint)
                            }
                            .padding(.horizontal, 24)
                            .padding(.vertical, 14)
                        }

                        ClipBetDarkDivider()
                    }

                    if let winner = selectedWinner {
                        // Payout breakdown
                        VStack(spacing: 4) {
                            Text("\(winner.betCount) winners share")
                                .font(.custom("DM Mono", size: 11))
                                .foregroundColor(ClipBetColors.textFaint)
                            Text(String(format: "$%.0f", event.winnerPool))
                                .font(.custom("Cormorant Garamond", size: 28))
                                .fontWeight(.light)
                                .foregroundColor(ClipBetColors.yes)
                        }
                        .padding(.vertical, 16)
                    }

                    // Confirm button
                    Button {
                        resolveEvent()
                    } label: {
                        Text("CONFIRM RESOLUTION")
                            .font(.custom("DM Mono", size: 13))
                            .kerning(2)
                            .foregroundColor(selectedWinner != nil ? ClipBetColors.dark : ClipBetColors.textFaint)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 16)
                            .background(selectedWinner != nil ? Color.white : Color.white.opacity(0.2))
                            .clipShape(RoundedRectangle(cornerRadius: 2))
                    }
                    .disabled(selectedWinner == nil)
                    .padding(.horizontal, 24)
                    .padding(.vertical, 16)

                    Text("This cannot be undone")
                        .font(.custom("DM Mono", size: 10))
                        .foregroundColor(ClipBetColors.no)
                        .padding(.bottom, 24)
                }
                .background(ClipBetColors.dark)
                .clipShape(RoundedRectangle(cornerRadius: 2))
            }
            .ignoresSafeArea(edges: .bottom)
        }
    }

    // MARK: - Cancel Confirm Overlay

    private var cancelConfirmOverlay: some View {
        ZStack {
            Color.black.opacity(0.5).ignoresSafeArea()
                .onTapGesture {
                    withAnimation { showCancelConfirm = false }
                }

            VStack(spacing: 20) {
                Text("Cancel Event?")
                    .font(.custom("Cormorant Garamond", size: 24))
                    .fontWeight(.light)
                    .foregroundColor(ClipBetColors.bg)

                Text("\(event.totalBettors) bettors will be fully refunded")
                    .font(.custom("DM Mono", size: 12))
                    .foregroundColor(ClipBetColors.textFaint)
                    .multilineTextAlignment(.center)

                VStack(spacing: 8) {
                    Button {
                        cancelEvent()
                    } label: {
                        Text("CANCEL & REFUND ALL")
                            .font(.custom("DM Mono", size: 13))
                            .kerning(1.6)
                            .foregroundColor(.white)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 16)
                            .background(ClipBetColors.no)
                            .clipShape(RoundedRectangle(cornerRadius: 2))
                    }

                    Button {
                        withAnimation { showCancelConfirm = false }
                    } label: {
                        Text("KEEP EVENT")
                            .font(.custom("DM Mono", size: 12))
                            .kerning(1.4)
                            .foregroundColor(ClipBetColors.textFaint)
                            .padding(.vertical, 12)
                    }
                }
            }
            .padding(28)
            .background(ClipBetColors.dark)
            .clipShape(RoundedRectangle(cornerRadius: 2))
            .padding(.horizontal, 32)
        }
    }

    // MARK: - Close Bets Confirm Overlay

    private var closeConfirmOverlay: some View {
        ZStack {
            Color.black.opacity(0.5).ignoresSafeArea()
                .onTapGesture {
                    withAnimation { showCloseConfirm = false }
                }

            VStack(spacing: 20) {
                Text("Close Bets?")
                    .font(.custom("Cormorant Garamond", size: 24))
                    .fontWeight(.light)
                    .foregroundColor(ClipBetColors.bg)

                Text("No new bets will be accepted. You can still resolve or cancel.")
                    .font(.custom("DM Mono", size: 12))
                    .foregroundColor(ClipBetColors.textFaint)
                    .multilineTextAlignment(.center)

                VStack(spacing: 8) {
                    Button {
                        closeBets()
                    } label: {
                        Text("CLOSE BETS")
                            .font(.custom("DM Mono", size: 13))
                            .kerning(1.6)
                            .foregroundColor(ClipBetColors.dark)
                            .frame(maxWidth: .infinity)
                            .padding(.vertical, 16)
                            .background(Color.white)
                            .clipShape(RoundedRectangle(cornerRadius: 2))
                    }

                    Button {
                        withAnimation { showCloseConfirm = false }
                    } label: {
                        Text("KEEP OPEN")
                            .font(.custom("DM Mono", size: 12))
                            .kerning(1.4)
                            .foregroundColor(ClipBetColors.textFaint)
                            .padding(.vertical, 12)
                    }
                }
            }
            .padding(28)
            .background(ClipBetColors.dark)
            .clipShape(RoundedRectangle(cornerRadius: 2))
            .padding(.horizontal, 32)
        }
    }

    // MARK: - Status Banners

    private var resolvedBanner: some View {
        VStack(spacing: 8) {
            Image(systemName: "checkmark.circle.fill")
                .font(.system(size: 24))
                .foregroundColor(ClipBetColors.yes)
            Text("Event Resolved")
                .font(.custom("DM Mono", size: 12))
                .kerning(1.4)
                .foregroundColor(ClipBetColors.yes)
            Text("Winnings have been distributed")
                .font(.custom("DM Mono", size: 10))
                .foregroundColor(ClipBetColors.textFaint)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 20)
        .background(ClipBetColors.yesFill)
        .clipShape(RoundedRectangle(cornerRadius: 2))
    }

    private var cancelledBanner: some View {
        VStack(spacing: 8) {
            Image(systemName: "xmark.circle.fill")
                .font(.system(size: 24))
                .foregroundColor(ClipBetColors.no)
            Text("Event Cancelled")
                .font(.custom("DM Mono", size: 12))
                .kerning(1.4)
                .foregroundColor(ClipBetColors.no)
            Text("All bettors have been refunded")
                .font(.custom("DM Mono", size: 10))
                .foregroundColor(ClipBetColors.textFaint)
        }
        .frame(maxWidth: .infinity)
        .padding(.vertical, 20)
        .background(ClipBetColors.noFill)
        .clipShape(RoundedRectangle(cornerRadius: 2))
    }

    // MARK: - Actions

    private func resolveEvent() {
        guard let winner = selectedWinner else { return }
        event.resolvedOutcomeId = winner.id
        event.status = .resolved
        event.resolvedAt = Date()
        withAnimation { showResolveSheet = false }

        // In production: trigger Stripe Connect transfers
        paymentManager.distributeWinnings(
            event: event,
            winningOutcomeId: winner.id
        ) { _ in }
    }

    private func cancelEvent() {
        event.status = .cancelled
        withAnimation { showCancelConfirm = false }

        // In production: trigger Stripe refunds
        paymentManager.processRefund { _ in }
    }

    private func closeBets() {
        event.status = .betsClosed
        event.closedAt = Date()
        withAnimation { showCloseConfirm = false }
    }
}

// MARK: - From Submissions/clipbet/ClipBetExperience.swift

//  ClipBetExperience.swift
//  ClipBet
//
//  Main App Clip experience. Entry point for the ClipBet prediction market.
//  Flow: Landing -> Place Bet -> Confirm (Apple Pay) -> Success
//
//  Scan QR at a venue. See the event. Place your bet. Done.
//

import SwiftUI

struct ClipBetExperience: ClipExperience {
    static let urlPattern = "clipbet.io/event/:eventId"
    static let clipName = "ClipBet"
    static let clipDescription = "Scan. Predict. Win. Hyperlocal prediction markets, no app, no account."
    static let teamName = "ClipBet"

    static let touchpoint: JourneyTouchpoint = .onSite
    static let invocationSource: InvocationSource = .qrCode

    let context: ClipContext

    // MARK: - Screen Flow

    enum Screen {
        case landing
        case placeBet
        case confirm
        case success
        case createEvent
        case dashboard
    }

    @State private var currentScreen: Screen = .landing
    @State private var event: PredictionEvent = ClipBetMockData.primaryEvent
    @State private var selectedOutcome: BetOutcome?
    @State private var betAmount: Double = 10
    @State private var nickname: String = ""
    @State private var email: String = ""
    @State private var customAmount: String = ""
    @State private var showCustomAmount = false
    @State private var appeared = false
    @State private var paymentManager = ClipBetPaymentManager()

    var body: some View {
        ZStack {
            ClipBetColors.bg.ignoresSafeArea()

            switch currentScreen {
            case .landing:
                landingView
                    .transition(.opacity)
            case .placeBet:
                placeBetView
                    .transition(.move(edge: .trailing).combined(with: .opacity))
            case .confirm:
                confirmView
                    .transition(.move(edge: .trailing).combined(with: .opacity))
            case .success:
                successView
                    .transition(.scale(scale: 0.95).combined(with: .opacity))
            case .createEvent:
                CreateEventFlow()
                    .transition(.move(edge: .trailing).combined(with: .opacity))
            case .dashboard:
                OrganizerDashboard()
                    .transition(.move(edge: .trailing).combined(with: .opacity))
            }
        }
        .animation(.easeInOut(duration: 0.3), value: currentScreen)
        .onAppear {
            withAnimation(.easeOut(duration: 0.6).delay(0.1)) {
                appeared = true
            }
        }
    }

    // MARK: - Landing View

    private var landingView: some View {
        ScrollView {
            VStack(spacing: 0) {

                // Brand + Status
                VStack(spacing: 16) {
                    Text("ClipBet")
                        .font(.custom("Cormorant Garamond", size: 32))
                        .fontWeight(.light)
                        .foregroundColor(ClipBetColors.textPrimary)
                        .opacity(appeared ? 1 : 0)
                        .offset(y: appeared ? 0 : 8)

                    StatusIndicator(status: event.status)
                }
                .padding(.top, 24)
                .padding(.bottom, 20)

                ClipBetDivider()

                // Event question
                VStack(spacing: 12) {
                    Text(event.name)
                        .font(.custom("Cormorant Garamond", size: 28))
                        .fontWeight(.light)
                        .foregroundColor(ClipBetColors.textPrimary)
                        .multilineTextAlignment(.center)
                        .lineSpacing(4)
                        .opacity(appeared ? 1 : 0)
                        .offset(y: appeared ? 0 : 12)

                    MonoLabel(text: event.location)
                }
                .padding(.horizontal, 32)
                .padding(.vertical, 28)

                ClipBetDivider()

                // Pool stats
                HStack(spacing: 0) {
                    StatColumn(value: event.formattedPool, label: "TOTAL POOL")
                    ClipBetVerticalDivider()
                    StatColumn(value: "\(event.totalBettors)", label: "BETTORS")
                    ClipBetVerticalDivider()
                    StatColumn(value: "5%", label: "PLATFORM FEE")
                }
                .padding(.vertical, 20)

                ClipBetDivider()

                // Outcomes
                VStack(spacing: 0) {
                    ForEach(Array(event.outcomes.enumerated()), id: \.element.id) { index, outcome in
                        OutcomeRow(
                            outcome: outcome,
                            percentage: event.percentage(for: outcome),
                            isFirst: index == 0
                        )
                        if index < event.outcomes.count - 1 {
                            ClipBetDivider()
                        }
                    }
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 16)

                ClipBetDivider()

                // CTA
                VStack(spacing: 12) {
                    ClipBetPrimaryButton(title: "PLACE A BET") {
                        withAnimation { currentScreen = .placeBet }
                    }

                    ClipBetSecondaryButton(title: "CREATE YOUR OWN EVENT") {
                        withAnimation { currentScreen = .createEvent }
                    }
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 24)

                // Organizer
                MonoLabel(text: "organized by \(event.organizer)")
                    .padding(.bottom, 8)

                MonoLabel(text: event.timeSinceCreated + " ago")
                    .padding(.bottom, 24)
            }
        }
        .scrollIndicators(.hidden)
    }

    // MARK: - Place Bet View

    private var placeBetView: some View {
        ScrollView {
            VStack(spacing: 0) {

                // Header
                HStack {
                    ClipBetBackButton {
                        withAnimation { currentScreen = .landing }
                    }
                    Spacer()
                }
                .padding(.horizontal, 24)
                .padding(.top, 16)

                Text("Place Your Bet")
                    .font(.custom("Cormorant Garamond", size: 28))
                    .fontWeight(.light)
                    .foregroundColor(ClipBetColors.textPrimary)
                    .padding(.top, 20)
                    .padding(.bottom, 8)

                MonoLabel(text: event.name)
                    .padding(.horizontal, 32)
                    .padding(.bottom, 24)

                ClipBetDivider()

                // Email
                VStack(alignment: .leading, spacing: 8) {
                    MonoLabelLeft(text: "EMAIL")
                    ClipBetTextField(
                        placeholder: "your@email.com",
                        text: $email,
                        keyboardType: .emailAddress
                    )
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 20)

                ClipBetDivider()

                // Nickname
                VStack(alignment: .leading, spacing: 8) {
                    HStack {
                        MonoLabelLeft(text: "NICKNAME")
                        Spacer()
                        Text("optional")
                            .font(.custom("DM Mono", size: 10))
                            .foregroundColor(ClipBetColors.textFaint)
                    }
                    ClipBetTextField(
                        placeholder: "Anonymous",
                        text: $nickname
                    )
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 20)

                ClipBetDivider()

                // Outcome selection
                VStack(alignment: .leading, spacing: 12) {
                    MonoLabelLeft(text: "SELECT OUTCOME")
                        .padding(.horizontal, 24)

                    ForEach(event.outcomes) { outcome in
                        let isSelected = selectedOutcome?.id == outcome.id
                        let isYes = event.outcomes.first?.id == outcome.id

                        Button {
                            withAnimation(.easeOut(duration: 0.2)) {
                                selectedOutcome = outcome
                            }
                        } label: {
                            HStack {
                                Circle()
                                    .fill(isSelected
                                          ? (isYes ? ClipBetColors.yes : ClipBetColors.no)
                                          : ClipBetColors.divider)
                                    .frame(width: 8, height: 8)

                                Text(outcome.name)
                                    .font(.custom("DM Mono", size: 14))
                                    .foregroundColor(isSelected ? ClipBetColors.textPrimary : ClipBetColors.textSecondary)

                                Spacer()

                                Text(String(format: "%.0f%%", event.percentage(for: outcome)))
                                    .font(.custom("Cormorant Garamond", size: 22))
                                    .fontWeight(.light)
                                    .foregroundColor(isSelected
                                                     ? (isYes ? ClipBetColors.yes : ClipBetColors.no)
                                                     : ClipBetColors.textFaint)
                            }
                            .padding(.horizontal, 20)
                            .padding(.vertical, 16)
                            .background(isSelected
                                        ? (isYes ? ClipBetColors.yesFill : ClipBetColors.noFill)
                                        : Color.clear)
                            .clipShape(RoundedRectangle(cornerRadius: 2))
                        }
                        .padding(.horizontal, 16)
                    }
                }
                .padding(.vertical, 20)

                ClipBetDivider()

                // Bet amount
                VStack(alignment: .leading, spacing: 12) {
                    MonoLabelLeft(text: "BET AMOUNT")
                        .padding(.horizontal, 24)

                    HStack(spacing: 8) {
                        ForEach([5.0, 10.0, 25.0], id: \.self) { amount in
                            AmountButton(
                                amount: amount,
                                isSelected: !showCustomAmount && betAmount == amount
                            ) {
                                showCustomAmount = false
                                customAmount = ""
                                betAmount = amount
                            }
                        }

                        Button {
                            showCustomAmount = true
                            betAmount = 0
                        } label: {
                            Text("CUSTOM")
                                .font(.custom("DM Mono", size: 12))
                                .kerning(1)
                                .foregroundColor(showCustomAmount ? ClipBetColors.bg : ClipBetColors.textSecondary)
                                .padding(.horizontal, 16)
                                .padding(.vertical, 12)
                                .background(showCustomAmount ? ClipBetColors.dark : Color.clear)
                                .overlay(
                                    RoundedRectangle(cornerRadius: 2)
                                        .stroke(ClipBetColors.divider, lineWidth: 1)
                                )
                                .clipShape(RoundedRectangle(cornerRadius: 2))
                        }
                    }
                    .padding(.horizontal, 24)

                    if showCustomAmount {
                        HStack {
                            Text("$")
                                .font(.custom("Cormorant Garamond", size: 24))
                                .fontWeight(.light)
                                .foregroundColor(ClipBetColors.textPrimary)
                            TextField("0", text: $customAmount)
                                .font(.custom("Cormorant Garamond", size: 24))
                                .fontWeight(.light)
                                .foregroundColor(ClipBetColors.textPrimary)
                                .keyboardType(.numberPad)
                                .onChange(of: customAmount) { _, newValue in
                                    betAmount = Double(newValue) ?? 0
                                }
                        }
                        .padding(.horizontal, 16)
                        .padding(.vertical, 12)
                        .background(ClipBetColors.surface)
                        .clipShape(RoundedRectangle(cornerRadius: 2))
                        .padding(.horizontal, 24)
                    }
                }
                .padding(.vertical, 20)

                ClipBetDivider()

                // Estimated return
                if let outcome = selectedOutcome, betAmount > 0 {
                    let est = event.estimatedReturn(betAmount: betAmount, for: outcome)
                    VStack(spacing: 4) {
                        MonoLabel(text: "ESTIMATED RETURN")
                        Text(String(format: "$%.2f", est))
                            .font(.custom("Cormorant Garamond", size: 36))
                            .fontWeight(.light)
                            .foregroundColor(ClipBetColors.yes)
                    }
                    .padding(.vertical, 20)

                    ClipBetDivider()
                }

                // Review button
                let canProceed = selectedOutcome != nil && betAmount >= event.minimumBet && !email.isEmpty
                ClipBetPrimaryButton(
                    title: "REVIEW & PAY",
                    icon: "apple.logo",
                    isEnabled: canProceed
                ) {
                    withAnimation { currentScreen = .confirm }
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 24)

                MonoLabel(text: "min bet: $\(Int(event.minimumBet))")
                    .padding(.bottom, 24)
            }
        }
        .scrollIndicators(.hidden)
    }

    // MARK: - Confirm View (Dark Modal)

    private var confirmView: some View {
        VStack(spacing: 0) {
            Spacer()

            VStack(spacing: 0) {
                // Header
                HStack {
                    Button {
                        withAnimation { currentScreen = .placeBet }
                    } label: {
                        HStack(spacing: 4) {
                            Image(systemName: "arrow.left")
                                .font(.system(size: 12))
                            Text("BACK")
                                .font(.custom("DM Mono", size: 11))
                                .kerning(1.6)
                        }
                        .foregroundColor(ClipBetColors.textFaint)
                    }
                    Spacer()
                }
                .padding(.horizontal, 24)
                .padding(.top, 24)

                Text("Confirm Bet")
                    .font(.custom("Cormorant Garamond", size: 28))
                    .fontWeight(.light)
                    .foregroundColor(ClipBetColors.bg)
                    .padding(.top, 16)
                    .padding(.bottom, 24)

                // Bet details
                VStack(spacing: 0) {
                    ConfirmRow(label: "EVENT", value: event.name, isMultiline: true)
                    ClipBetDarkDivider()
                    ConfirmRow(label: "PREDICTION", value: selectedOutcome?.name ?? "")
                    ClipBetDarkDivider()
                    ConfirmRow(label: "AMOUNT", value: String(format: "$%.0f", betAmount))
                    ClipBetDarkDivider()
                    if let outcome = selectedOutcome {
                        let est = event.estimatedReturn(betAmount: betAmount, for: outcome)
                        ConfirmRow(label: "EST. RETURN", value: String(format: "$%.2f", est), valueColor: ClipBetColors.yes)
                        ClipBetDarkDivider()
                    }
                    ConfirmRow(label: "AS", value: nickname.isEmpty ? "Anonymous" : nickname)
                    ClipBetDarkDivider()
                    ConfirmRow(label: "CONTACT", value: email)
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 16)

                // Payment status
                ClipBetPaymentStatus(state: paymentManager.paymentState)
                    .padding(.horizontal, 24)

                Spacer()

                // Apple Pay button + card fallback
                ClipBetApplePayButton(
                    amount: betAmount,
                    isEnabled: paymentManager.paymentState != .processing,
                    isProcessing: paymentManager.paymentState == .processing,
                    onTap: { processApplePayment() },
                    onCardFallback: { processCardPayment() }
                )
                .padding(.horizontal, 24)
                .padding(.bottom, 32)
            }
            .background(ClipBetColors.dark)
            .clipShape(RoundedRectangle(cornerRadius: 2))
        }
        .ignoresSafeArea(edges: .bottom)
    }

    // MARK: - Success View

    private var successView: some View {
        ScrollView {
            VStack(spacing: 0) {
                VStack(spacing: 16) {
                    Image(systemName: "checkmark")
                        .font(.system(size: 32, weight: .light))
                        .foregroundColor(ClipBetColors.yes)
                        .padding(.top, 40)

                    Text("You're In")
                        .font(.custom("Cormorant Garamond", size: 36))
                        .fontWeight(.light)
                        .foregroundColor(ClipBetColors.textPrimary)

                    MonoLabel(text: "Bet placed successfully")
                }
                .padding(.bottom, 28)

                ClipBetDivider()

                // Receipt
                VStack(spacing: 0) {
                    ReceiptRow(label: "EVENT", value: event.name)
                    ReceiptRow(label: "YOUR PICK", value: selectedOutcome?.name ?? "")
                    ReceiptRow(label: "AMOUNT", value: String(format: "$%.0f", betAmount))
                    if let outcome = selectedOutcome {
                        let est = event.estimatedReturn(betAmount: betAmount, for: outcome)
                        ReceiptRow(label: "EST. RETURN", value: String(format: "$%.2f", est))
                    }
                    ReceiptRow(label: "NICKNAME", value: nickname.isEmpty ? "Anonymous" : nickname)
                    if case .success(let txId) = paymentManager.paymentState {
                        ReceiptRow(label: "TRANSACTION", value: txId)
                    }
                }
                .padding(.horizontal, 24)
                .padding(.vertical, 20)

                ClipBetDivider()

                // Pool standings
                VStack(spacing: 16) {
                    MonoLabel(text: "CURRENT STANDINGS")
                        .padding(.top, 20)

                    ForEach(event.outcomes) { outcome in
                        let pct = event.percentage(for: outcome)
                        let isYes = event.outcomes.first?.id == outcome.id
                        let isYours = outcome.id == selectedOutcome?.id

                        VStack(alignment: .leading, spacing: 6) {
                            HStack {
                                Text(outcome.name)
                                    .font(.custom("DM Mono", size: 13))
                                    .foregroundColor(ClipBetColors.textPrimary)

                                if isYours {
                                    ClipBetTag(text: "YOUR PICK")
                                }

                                Spacer()

                                Text(String(format: "%.0f%%", pct))
                                    .font(.custom("Cormorant Garamond", size: 24))
                                    .fontWeight(.light)
                                    .foregroundColor(isYes ? ClipBetColors.yes : ClipBetColors.no)
                            }

                            GeometryReader { geo in
                                ZStack(alignment: .leading) {
                                    Rectangle()
                                        .fill(ClipBetColors.divider)
                                        .frame(height: 3)
                                    Rectangle()
                                        .fill(isYes ? ClipBetColors.yes : ClipBetColors.no)
                                        .frame(width: geo.size.width * (pct / 100), height: 3)
                                }
                            }
                            .frame(height: 3)
                        }
                        .padding(.horizontal, 24)
                    }
                }
                .padding(.bottom, 24)

                ClipBetDivider()

                // Notification opt-in
                VStack(spacing: 12) {
                    MonoLabel(text: "GET NOTIFIED WHEN RESULTS ARE IN")

                    Button { } label: {
                        HStack(spacing: 8) {
                            Image(systemName: "bell")
                                .font(.system(size: 14))
                            Text("ENABLE NOTIFICATIONS")
                                .font(.custom("DM Mono", size: 12))
                                .kerning(1.6)
                        }
                        .foregroundColor(ClipBetColors.textPrimary)
                        .padding(.horizontal, 20)
                        .padding(.vertical, 14)
                        .overlay(
                            RoundedRectangle(cornerRadius: 2)
                                .stroke(ClipBetColors.divider, lineWidth: 1)
                        )
                    }
                }
                .padding(.vertical, 24)

                // Escrow info
                VStack(spacing: 4) {
                    MonoLabel(text: "FUNDS HELD IN ESCROW")
                    Text("Organizer has 24h to resolve. If unresolved, you get a full refund.")
                        .font(.custom("DM Mono", size: 10))
                        .foregroundColor(ClipBetColors.textFaint)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal, 32)
                }
                .padding(.bottom, 32)
            }
        }
        .scrollIndicators(.hidden)
    }

    // MARK: - Payment Actions

    private func processApplePayment() {
        paymentManager.selectedMethod = .applePay
        paymentManager.processBet(
            amount: betAmount,
            eventId: event.id,
            outcomeId: selectedOutcome?.id ?? UUID(),
            email: email,
            nickname: nickname.isEmpty ? "Anonymous" : nickname
        ) { success in
            if success {
                // Update pool with user bet
                if let idx = event.outcomes.firstIndex(where: { $0.id == selectedOutcome?.id }) {
                    event.outcomes[idx].totalAmount += betAmount
                    event.outcomes[idx].betCount += 1
                }
                withAnimation { currentScreen = .success }
            }
            // On failure, payment status view shows error, user can retry
        }
    }

    private func processCardPayment() {
        paymentManager.selectedMethod = .card
        paymentManager.processBet(
            amount: betAmount,
            eventId: event.id,
            outcomeId: selectedOutcome?.id ?? UUID(),
            email: email,
            nickname: nickname.isEmpty ? "Anonymous" : nickname
        ) { success in
            if success {
                if let idx = event.outcomes.firstIndex(where: { $0.id == selectedOutcome?.id }) {
                    event.outcomes[idx].totalAmount += betAmount
                    event.outcomes[idx].betCount += 1
                }
                withAnimation { currentScreen = .success }
            }
        }
    }
}

